307	// UpdateWorkOrder updates a work order. Only maintenance role users can update.
308	func (h *WorkOrderHandler) UpdateWorkOrder(c echo.Context) error {
309		id := c.Param("id")
310		if id == "" {
311			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
312				Error: "Work order ID is required",
313				Code:  http.StatusBadRequest,
314			})
315		}
316	
317		wo, err := h.repo.GetWorkOrderByID(id)
318		if err != nil || wo == nil {
319			return c.JSON(http.StatusNotFound, models.ErrorResponse{
320				Error:   "Work order not found",
321				Code:    http.StatusNotFound,
322				Details: "No work order found with the given ID",
323			})
324		}
325	
326		var body struct {
327			Status      *string `json:"status"`
328			Description *string `json:"description"`
329			Location    *string `json:"location"`
330			AssignedTo  *string `json:"assigned_to"`
331		}
332		if err := c.Bind(&body); err != nil {
333			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
334				Error: "Invalid request body",
335				Code:  http.StatusBadRequest,
336			})
337		}
338	
339		if body.Status != nil {
340			// Prevent status changes from terminal states
341			terminalStatuses := map[string]bool{"completed": true, "closed": true, "cancelled": true}
342			if terminalStatuses[wo.Status] {
343				return c.JSON(http.StatusBadRequest, models.ErrorResponse{
344					Error:   "Validation failed",
345					Code:    http.StatusBadRequest,
346					Details: "Cannot change status of a completed, closed, or cancelled work order",
347				})
348			}
349	
350			validStatuses := map[string]bool{
351				"submitted": true, "dispatched": true, "in_progress": true,
352				"completed": true, "closed": true, "cancelled": true,
353			}
354			if !validStatuses[*body.Status] {
355				return c.JSON(http.StatusBadRequest, models.ErrorResponse{
356					Error:   "Validation failed",
357					Code:    http.StatusBadRequest,
358					Details: "Invalid status value",
359				})
360			}
361			wo.Status = *body.Status
362		}
363		if body.Description != nil {
364			wo.Description = *body.Description
365		}
366		if body.Location != nil {
367			wo.Location = *body.Location
368		}
369		if body.AssignedTo != nil {
370			wo.AssignedTo = body.AssignedTo
371		}
372	
373		if err := h.repo.UpdateWorkOrder(wo); err != nil {
374			logrus.WithError(err).Error("Failed to update work order")
375			return c.JSON(http.StatusInternalServerError, models.ErrorResponse{
376				Error: "Failed to update work order",
377				Code:  http.StatusInternalServerError,
378			})
379		}
380	
381		userID := middleware.GetUserID(c)
382		details, _ := json.Marshal(map[string]string{"wo_id": id})
383		h.repo.CreateAuditLog(&models.AuditLogEntry{
384			UserID:     userID,
385			Action:     "update_work_order",
386			EntityType: "work_order",
387			EntityID:   id,
388			Details:    details,
389		})
390	
391		logrus.WithFields(logrus.Fields{
392			"user_id": userID,
393			"wo_id":   id,
394		}).Info("Work order updated")
395	
396		return c.JSON(http.StatusOK, wo)
397	}
