400	func (h *WorkOrderHandler) CloseWorkOrder(c echo.Context) error {
401		id := c.Param("id")
402		if id == "" {
403			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
404				Error: "Work order ID is required",
405				Code:  http.StatusBadRequest,
406			})
407		}
408	
409		wo, err := h.repo.GetWorkOrderByID(id)
410		if err != nil || wo == nil {
411			return c.JSON(http.StatusNotFound, models.ErrorResponse{
412				Error:   "Work order not found",
413				Code:    http.StatusNotFound,
414				Details: "No work order found with the given ID",
415			})
416		}
417	
418		if wo.Status == "completed" || wo.Status == "closed" || wo.Status == "cancelled" {
419			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
420				Error:   "Work order already closed or cancelled",
421				Code:    http.StatusBadRequest,
422				Details: "This work order has already been completed, closed, or cancelled",
423			})
424		}
425	
426		var req models.CloseWorkOrderRequest
427		if err := c.Bind(&req); err != nil {
428			return c.JSON(http.StatusBadRequest, models.ErrorResponse{
429				Error: "Invalid request body",
430				Code:  http.StatusBadRequest,
431			})
432		}
433	
434		now := time.Now()
435		wo.PartsCost = req.PartsCost
436		wo.LaborCost = req.LaborCost
437		wo.Status = "completed"
438		wo.ClosedAt = &now
