251	  try {
252	    const token = await opts.getAuthToken();
253	    const authHeader = { Authorization: `Bearer ${token}` };
254	
255	    // Check members expiring soon.
256	    const membersResp = await fetch(
257	      `${opts.backendUrl}/api/v1/members?page=1&page_size=100`,
258	      { headers: authHeader },
259	    );
