463	// ApplyUpdate accepts an offline update package (multipart .zip or .sql upload),
464	// stages and applies all SQL migrations in lexicographic order, and installs any
465	// included backend binary / frontend asset overrides into DATA_DIR/active/.
466	//
467	// Before any changes are made:
468	//   - A pg_dump snapshot of the current database is written to DATA_DIR/backups/.
469	//   - The current application artifacts in DATA_DIR/active/ (if any) are copied to
470	//     DATA_DIR/versions/<timestamp>/ so a subsequent rollback can restore both DB
471	//     and application binaries atomically.
472	//
473	// If no file is uploaded the handler falls back to a pre-staged pending directory.
474	// After a successful apply the staging directory is renamed applied_<timestamp>.
475	func (h *SystemHandler) ApplyUpdate(c echo.Context) error {
476		userID := middleware.GetUserID(c)
477	
478		// Use a single timestamp throughout so DB snapshot, artifact snapshot, and
479		// version history all share the same epoch label.
480		timestamp := time.Now().UTC().Format("20060102T150405Z")
481		updateDir := filepath.Join(h.dataDir, "updates", "pending")
482	
483		// ── Stage the uploaded package ────────────────────────────────────────────
484		var tmpZip string // only set when a ZIP is uploaded
485	
486		uploadedFile, uploadErr := c.FormFile("file")
487		if uploadErr == nil {
488			src, err := uploadedFile.Open()
489			if err != nil {
490				return c.JSON(http.StatusInternalServerError, models.ErrorResponse{
491					Error: "Failed to read uploaded file",
492					Code:  http.StatusInternalServerError,
493				})
494			}
495			defer src.Close()
496	
497			if err := os.MkdirAll(updateDir, 0755); err != nil {
498				return c.JSON(http.StatusInternalServerError, models.ErrorResponse{
499					Error: "Failed to prepare update directory",
500					Code:  http.StatusInternalServerError,
501				})
502			}
503	
504			ext := strings.ToLower(filepath.Ext(uploadedFile.Filename))
505			switch ext {
506			case ".zip":
507				tmpZip = filepath.Join(h.dataDir, "updates", "upload_"+timestamp+".zip")
508				dst, err := os.Create(tmpZip)
509				if err != nil {
510					return c.JSON(http.StatusInternalServerError, models.ErrorResponse{
511						Error: "Failed to save uploaded package",
512						Code:  http.StatusInternalServerError,
513					})
514				}
515				if _, err := io.Copy(dst, src); err != nil {
516					dst.Close()
517					os.Remove(tmpZip)
518					return c.JSON(http.StatusInternalServerError, models.ErrorResponse{
519						Error: "Failed to write uploaded package",
520						Code:  http.StatusInternalServerError,
521					})
522				}
523				dst.Close()
524				if err := extractZIPToDir(tmpZip, updateDir); err != nil {
525					os.Remove(tmpZip)
526					return c.JSON(http.StatusBadRequest, models.ErrorResponse{
527						Error:   "Failed to extract SQL migrations from package",
528						Code:    http.StatusBadRequest,
529						Details: err.Error(),
530					})
531				}
532			case ".sql":
533				dst, err := os.Create(filepath.Join(updateDir, filepath.Base(uploadedFile.Filename)))
534				if err != nil {
535					return c.JSON(http.StatusInternalServerError, models.ErrorResponse{
536						Error: "Failed to stage SQL migration",
537						Code:  http.StatusInternalServerError,
538					})
539				}
540				if _, err := io.Copy(dst, src); err != nil {
541					dst.Close()
542					return c.JSON(http.StatusInternalServerError, models.ErrorResponse{
543						Error: "Failed to write SQL migration",
544						Code:  http.StatusInternalServerError,
545					})
546				}
547				dst.Close()
548			default:
549				return c.JSON(http.StatusBadRequest, models.ErrorResponse{
550					Error:   "Unsupported package format",
551					Code:    http.StatusBadRequest,
552					Details: "Upload a .zip package or a single .sql migration file",
553				})
554			}
555		} else {
556			// No upload — require a pre-staged pending directory.
557			if _, err := os.Stat(updateDir); os.IsNotExist(err) {
558				return c.JSON(http.StatusNotFound, models.ErrorResponse{
559					Error:   "No pending update found",
560					Code:    http.StatusNotFound,
561					Details: "Upload a .zip or .sql package via multipart, or stage files in " + updateDir,
562				})
563			}
564		}
565	
566		// ── Pre-update snapshots (DB + artifacts) ─────────────────────────────────
567		// Capture the CURRENT state before any mutation so Rollback has an exact target.
568	
569		fromVersion := h.currentVersion()
570	
571		preBackupFile, backupErr := h.preUpdateBackup()
572		if backupErr != nil {
573			logrus.WithError(backupErr).Warn("Pre-update DB snapshot failed; DB rollback to this version will not be available")
574			preBackupFile = ""
575		}
576	
577		artifactDir, artifactErr := h.snapshotArtifacts(timestamp)
578		if artifactErr != nil {
579			logrus.WithError(artifactErr).Warn("Pre-update artifact snapshot failed; app rollback to this version will not be available")
580			artifactDir = ""
581		}
582	
583		// ── Install new application artifacts from ZIP ────────────────────────────
584		// Extract backend/ and frontend/ subdirectories from the uploaded ZIP into
585		// DATA_DIR/active/ so Electron picks them up on next launch.
586		if tmpZip != "" {
587			if err := extractZIPArtifacts(tmpZip, h.activeDir()); err != nil {
588				logrus.WithError(err).Warn("Failed to extract application artifacts from package; SQL migrations will still be applied")
589			}
590			os.Remove(tmpZip)
591		}
592	
593		// ── Apply SQL migrations ──────────────────────────────────────────────────
594		entries, err := os.ReadDir(updateDir)
595		if err != nil {
596			return c.JSON(http.StatusInternalServerError, models.ErrorResponse{
597				Error: "Failed to read update package",
598				Code:  http.StatusInternalServerError,
599			})
600		}
601		// Sort lexicographically so migrations run in the documented order (H-01).
602		sort.Slice(entries, func(i, j int) bool {
603			return entries[i].Name() < entries[j].Name()
604		})
605	
606		applied := 0
607		for _, entry := range entries {
608			if entry.IsDir() || filepath.Ext(entry.Name()) != ".sql" {
609				continue
610			}
611			sqlPath := filepath.Join(updateDir, entry.Name())
612			sqlBytes, err := os.ReadFile(sqlPath)
613			if err != nil {
614				logrus.WithError(err).WithField("file", entry.Name()).Error("Failed to read SQL migration file")
615				return c.JSON(http.StatusInternalServerError, models.ErrorResponse{
616					Error:   "Failed to read migration file",
617					Code:    http.StatusInternalServerError,
618					Details: entry.Name(),
619				})
620			}
