423	// This is what installs new application binaries and frontend assets when an
424	// offline update package is applied.
425	func extractZIPArtifacts(zipPath, activeDir string) error {
426		r, err := zip.OpenReader(zipPath)
427		if err != nil {
428			return fmt.Errorf("open zip: %w", err)
429		}
430		defer r.Close()
431		for _, f := range r.File {
432			// Normalise separators for prefix matching.
433			name := filepath.ToSlash(f.Name)
434			if !strings.HasPrefix(name, "backend/") && !strings.HasPrefix(name, "frontend/") {
435				continue
436			}
437			dest := filepath.Join(activeDir, filepath.FromSlash(name))
438			if f.FileInfo().IsDir() {
439				_ = os.MkdirAll(dest, 0755)
440				continue
441			}
442			rc, err := f.Open()
443			if err != nil {
444				return fmt.Errorf("open %s: %w", f.Name, err)
445			}
446			data, err := io.ReadAll(rc)
447			rc.Close()
448			if err != nil {
449				return fmt.Errorf("read %s: %w", f.Name, err)
450			}
451			if err := os.MkdirAll(filepath.Dir(dest), 0755); err != nil {
452				return err
453			}
454			if err := os.WriteFile(dest, data, f.Mode()); err != nil {
455				return fmt.Errorf("write %s: %w", dest, err)
456			}
457		}
