		"user_id":       userID,
		"version":       version,
		"migrations":    applied,
		"applied_path":  appliedDir,
		"artifact_dir":  artifactDir,
	}).Info("Offline update applied")

	return c.JSON(http.StatusOK, map[string]interface{}{
		"version":          version,
		"status":           "applied",
		"migrations":       applied,
		"applied_at":       timestamp,
		"restart_required": true,
	})"}

