239	// preUpdateBackup runs pg_dump before applying an update so rollback has a precise snapshot.
240	func (h *SystemHandler) preUpdateBackup() (string, error) {
241		backupDir := filepath.Join(h.dataDir, "backups")
242		if err := os.MkdirAll(backupDir, 0750); err != nil {
243			return "", fmt.Errorf("create backup dir: %w", err)
244		}
245		timestamp := time.Now().UTC().Format("20060102T150405Z")
246		backupFile := filepath.Join(backupDir, fmt.Sprintf("pre_update_%s.sql", timestamp))
247		cmd := exec.Command("pg_dump", "--dbname", h.databaseURL, "--file", backupFile, "--format=plain", "--no-password")
248		if output, err := cmd.CombinedOutput(); err != nil {
249			return "", fmt.Errorf("pg_dump: %w (output: %s)", err, string(output))
250		}
251		return backupFile, nil
252	}
