2	import { BrowserRouter, Routes, Route, Navigate } from 'react-router-dom';
3	import { useAuth } from './hooks/useAuth';
4	import { ROUTE_CONFIG } from './routeConfig';
5	import Layout from './components/common/Layout';
6	import LoginPage from './components/admin/LoginPage';
7	import DashboardPage from './components/admin/DashboardPage';
8	import UsersPage from './components/admin/UsersPage';
9	import SKUListPage from './components/inventory/SKUListPage';
10	import SKUDetailPage from './components/inventory/SKUDetailPage';
11	import StocktakePage from './components/inventory/StocktakePage';
12	import LearningPage from './components/learning/LearningPage';
13	import WorkOrdersPage from './components/workorders/WorkOrdersPage';
14	import WorkOrderDetailPage from './components/workorders/WorkOrderDetailPage';
15	import MembersPage from './components/members/MembersPage';
16	import MemberDetailPage from './components/members/MemberDetailPage';
17	import RateTablesPage from './components/charges/RateTablesPage';
18	import StatementsPage from './components/charges/StatementsPage';
19	import SystemConfigPage from './components/admin/SystemConfigPage';
20	import ForcePasswordChangePage from './components/admin/ForcePasswordChangePage';
21	
22	/** Returns the role list for a given path from the canonical ROUTE_CONFIG. */
23	function routeRoles(path: string): string[] {
24	  return ROUTE_CONFIG.find(r => r.path === path)?.roles ?? [];
25	}
26	
27	function ProtectedRoute({ children }: { children: React.ReactNode }) {
28	  const { isAuthenticated, user, bootstrapping } = useAuth();
29	  if (bootstrapping) return null;
30	  if (!isAuthenticated) return <Navigate to="/login" replace />;
31	  if (user?.must_change_password) return <ForcePasswordChangePage />;
32	  return <Layout>{children}</Layout>;
33	}
34	
35	function RoleRoute({ children, roles }: { children: React.ReactNode; roles: string[] }) {
36	  const { user, isAuthenticated, bootstrapping } = useAuth();
37	  if (bootstrapping) return null;
38	  if (!isAuthenticated) return <Navigate to="/login" replace />;
39	  if (user?.must_change_password) return <ForcePasswordChangePage />;
40	  if (user && !roles.includes(user.role)) return <Navigate to="/" replace />;
41	  return <Layout>{children}</Layout>;
42	}
43	
44	export default function App() {
45	  const { isAuthenticated } = useAuth();
46	
47	  return (
48	    <BrowserRouter>
49	      <Routes>
50	        <Route path="/login" element={isAuthenticated ? <Navigate to="/" replace /> : <LoginPage />} />
51	        <Route path="/" element={<ProtectedRoute><DashboardPage /></ProtectedRoute>} />
52	        {/* /dashboard is an alias for / — referenced by nav shortcuts and post-login redirect */}
53	        <Route path="/dashboard" element={<Navigate to="/" replace />} />
54	        <Route path="/users" element={<RoleRoute roles={routeRoles('/users')}><UsersPage /></RoleRoute>} />
55	        <Route path="/skus" element={<RoleRoute roles={routeRoles('/skus')}><SKUListPage /></RoleRoute>} />
56	        <Route path="/skus/:id" element={<RoleRoute roles={routeRoles('/skus/:id')}><SKUDetailPage /></RoleRoute>} />
57	        <Route path="/stocktakes" element={<RoleRoute roles={routeRoles('/stocktakes')}><StocktakePage /></RoleRoute>} />
58	        <Route path="/stocktakes/:id" element={<RoleRoute roles={routeRoles('/stocktakes/:id')}><StocktakePage /></RoleRoute>} />
59	        <Route path="/learning" element={<ProtectedRoute><LearningPage /></ProtectedRoute>} />
60	        <Route path="/work-orders" element={<ProtectedRoute><WorkOrdersPage /></ProtectedRoute>} />
61	        <Route path="/work-orders/:id" element={<ProtectedRoute><WorkOrderDetailPage /></ProtectedRoute>} />
62	        <Route path="/members" element={<RoleRoute roles={routeRoles('/members')}><MembersPage /></RoleRoute>} />
63	        <Route path="/members/:id" element={<RoleRoute roles={routeRoles('/members/:id')}><MemberDetailPage /></RoleRoute>} />
64	        <Route path="/rate-tables" element={<RoleRoute roles={routeRoles('/rate-tables')}><RateTablesPage /></RoleRoute>} />
65	        <Route path="/statements" element={<RoleRoute roles={routeRoles('/statements')}><StatementsPage /></RoleRoute>} />
66	        <Route path="/system-config" element={<RoleRoute roles={routeRoles('/system-config')}><SystemConfigPage /></RoleRoute>} />
67	        <Route path="*" element={<Navigate to="/" replace />} />
68	      </Routes>
69	    </BrowserRouter>
70	  );
71	}
