21	import { setupTray, cleanupTray } from './tray';
22	
23	// embedded-postgres is an optional dependency — only available in packaged Electron builds.
24	// Dynamic import allows the renderer/web build to compile without it installed.
25	// eslint-disable-next-line @typescript-eslint/no-explicit-any
26	let EmbeddedPostgresClass: any = null;
27	(async () => {
28	  try {
29	    // @ts-ignore — embedded-postgres is an optional runtime dep; types not installed
30	    const mod = await import('embedded-postgres');
31	    EmbeddedPostgresClass = mod.default ?? mod;
32	  } catch {
33	    // Optional dependency not installed — will use external database
34	  }
35	})();
36	
37	// ─── Constants ────────────────────────────────────────────────────────────────
38	
39	const IS_DEV = !app.isPackaged;
40	const BACKEND_PORT = parseInt(process.env.BACKEND_PORT ?? '8080', 10);
41	const BACKEND_URL = `http://localhost:${BACKEND_PORT}`;
42	
43	// ─── State ────────────────────────────────────────────────────────────────────
44	
45	let mainWindow: BrowserWindow | null = null;
46	let backendProcess: ChildProcess | null = null;
47	// eslint-disable-next-line @typescript-eslint/no-explicit-any
48	let embeddedPg: any | null = null;
49	const windows = new Set<BrowserWindow>();
50	
51	// ─── Backend subprocess ───────────────────────────────────────────────────────
52	
53	/**
54	 * Resolves the backend binary to run.
55	 *
56	 * Priority order:
57	 *  1. DATA_DIR/active/backend/medops-server[.exe]  — installed by an offline update package
58	 *  2. process.resourcesPath/backend/medops-server[.exe]  — bundled at packaging time
59	 *
60	 * In dev mode (IS_DEV) the backend is assumed to be running externally (Docker / go run)
61	 * and null is returned so startBackend waits on the health endpoint instead.
62	 */
63	function getBackendBinary(): string | null {
64	  if (IS_DEV) return null; // dev mode: backend runs externally (Docker / go run)
65	
66	  const binaryName = process.platform === 'win32' ? 'medops-server.exe' : 'medops-server';
67	
68	  // 1. Check for an active override installed by an offline update.
69	  const userDataDir = app.getPath('userData');
70	  const dataDir = join(userDataDir, 'data');
71	  const activeOverride = join(dataDir, 'active', 'backend', binaryName);
72	  if (existsSync(activeOverride)) {
73	    console.log('[main] Using active binary override:', activeOverride);
74	    return activeOverride;
75	  }
76	
77	  // 2. Fall back to the binary bundled at packaging time.
78	  const candidate = join(process.resourcesPath, 'backend', binaryName);
79	  return existsSync(candidate) ? candidate : null;
80	}
81	
82	/**
83	 * Resolves the frontend assets path to load in the renderer window.
84	 *
85	 * Priority order:
86	 *  1. DATA_DIR/active/frontend/index.html  — installed by an offline update package
87	 *  2. __dirname/../dist/index.html         — bundled at packaging time
88	 *
89	 * In dev mode the Vite dev server URL is used instead.
90	 */
91	function getFrontendPath(): string {
92	  const VITE_DEV_URL = process.env.VITE_DEV_URL ?? 'http://localhost:3000';
93	  if (IS_DEV) return VITE_DEV_URL;
94	
95	  const userDataDir = app.getPath('userData');
96	  const dataDir = join(userDataDir, 'data');
97	  const activeFrontend = join(dataDir, 'active', 'frontend', 'index.html');
98	  if (existsSync(activeFrontend)) {
99	    console.log('[main] Using active frontend override:', activeFrontend);
100	    return activeFrontend;
101	  }
102	
103	  return join(__dirname, '..', 'dist', 'index.html');
104	}
