106	// startEmbeddedDatabase starts the bundled PostgreSQL instance via the
107	// `embedded-postgres` package (required at packaging time).
108	// In development mode the package is optional and the dev DATABASE_URL is used instead.
109	async function startEmbeddedDatabase(): Promise<string> {
110	  if (!EmbeddedPostgresClass) {
111	    if (!IS_DEV) {
112	      // Packaged build — embedded-postgres must be present; abort rather than silently
113	      // connecting to an unanticipated external database.
114	      dialog.showErrorBox(
115	        'MedOps — startup error',
116	        'Embedded database module not found. The installation may be corrupt. Please reinstall MedOps.',
117	      );
118	      app.quit();
119	      // Return is unreachable after quit but satisfies the type-checker.
120	      return '';
121	    }
122	    // Development: allow override via env so `go run` / Docker backends work alongside Electron.
123	    console.warn('[main] embedded-postgres not available — dev mode, using DATABASE_URL');
124	    return process.env.DATABASE_URL ?? 'postgres://medops:medops@localhost:5432/medops';
125	  }
126	  embeddedPg = new EmbeddedPostgresClass({
127	    port: 5433,
128	    user: 'medops',
129	    password: 'medops',
130	    database: 'medops',
131	    dataDir: join(app.getPath('userData'), 'pgdata'),
132	  });
133	  await embeddedPg.initialise();
134	  await embeddedPg.start();
135	  console.log('[main] Embedded PostgreSQL started on port 5433');
136	  return 'postgres://medops:medops@localhost:5433/medops';
137	}
138	
139	function startBackend(): Promise<void> {
140	  return new Promise(async (resolve, reject) => {
141	    const binary = getBackendBinary();
142	
143	    if (!binary) {
144	      // Dev mode or binary not found — assume backend is already running
145	      console.log('[main] Backend binary not found — assuming external backend at', BACKEND_URL);
146	      waitForBackend(20, resolve, reject);
147	      return;
148	    }
149	
150	    console.log('[main] Starting backend:', binary);
151	
152	    const userDataDir = join(app.getPath('userData'), 'data');
153	    const migrationsPath = join(process.resourcesPath, 'backend', 'migrations');
154	
155	    // Ensure secrets exist before starting backend (generates on first run)
156	    const secrets = ensureSecrets(app.getPath('userData'));
157	
158	    let databaseUrl: string;
159	    try {
160	      databaseUrl = await startEmbeddedDatabase();
161	      console.log('[main] Embedded PostgreSQL started at', databaseUrl);
162	    } catch (err) {
163	      reject(new Error(`Failed to start embedded database: ${(err as Error).message}`));
164	      return;
165	    }
166	
167	    backendProcess = spawn(binary, [], {
168	      env: {
169	        ...process.env,
170	        PORT: String(BACKEND_PORT),
171	        MIGRATIONS_PATH: migrationsPath,
172	        DATA_DIR: userDataDir,
173	        LOG_LEVEL: 'info',
174	        DATABASE_URL: databaseUrl,
175	        JWT_SECRET: secrets.jwtSecret,
176	        ENCRYPT_KEY: secrets.encryptKey,
177	        HMAC_SIGNING_KEY: secrets.hmacKey,
178	        TENANT_ID: 'default',
179	      },
180	      stdio: ['ignore', 'pipe', 'pipe'],
181	    });
182	
183	    backendProcess.stdout?.on('data', (d: Buffer) =>
184	      console.log('[backend]', d.toString().trim()),
185	    );
186	    backendProcess.stderr?.on('data', (d: Buffer) =>
187	      console.error('[backend]', d.toString().trim()),
188	    );
189	    backendProcess.on('exit', (code) => {
190	      console.warn('[main] Backend exited with code', code);
191	      backendProcess = null;
192	    });
193	
194	    // Wait for backend to become ready
195	    waitForBackend(60, resolve, reject);
196	  });
197	}
198	
199	function waitForBackend(maxAttempts: number, resolve: () => void, reject: (e: Error) => void): void {
200	  let attempts = 0;
201	  const check = (): void => {
202	    attempts++;
203	    fetch(`${BACKEND_URL}/api/v1/health`)
204	      .then((r) => {
205	        if (r.ok) {
206	          console.log('[main] Backend ready after', attempts, 'attempt(s)');
207	          resolve();
208	        } else {
209	          retry();
210	        }
211	      })
212	      .catch(() => retry());
213	  };
214	  const retry = (): void => {
215	    if (attempts >= maxAttempts) {
216	      reject(new Error(`Backend did not become ready after ${maxAttempts} attempts`));
217	      return;
218	    }
219	    setTimeout(check, 1000);
220	  };
221	  check();
222	}
223	
224	// ─── Restart flag watcher ─────────────────────────────────────────────────────
225	
226	/**
227	 * watchRestartFlag polls for the sentinel file written by the backend's Rollback handler
228	 * (DATA_DIR/restart.flag).  When found it:
229	 *  1. Removes the flag so the watcher does not trigger again.
230	 *  2. Stops the backend subprocess.
231	 *  3. Starts a new backend subprocess from the (now-restored) active binary.
232	 *  4. Reloads all renderer windows so they pick up the restored frontend assets.
233	 *  5. Shows a system tray / desktop notification.
234	 *
235	 * This implements the "offline restart" leg of the version rollback — the database
236	 * has already been restored by the time the flag is written.
237	 */
238	function watchRestartFlag(dataDir: string): void {
239	  const flagPath = join(dataDir, 'restart.flag');
240	  let handling = false;
241	
242	  const check = async (): Promise<void> => {
243	    if (handling) return;
244	    if (!existsSync(flagPath)) return;
245	
246	    handling = true;
247	    let version = 'previous version';
248	    try {
249	      version = readFileSync(flagPath, 'utf8').trim() || version;
250	      unlinkSync(flagPath);
251	    } catch {
252	      // Best-effort flag removal; proceed regardless.
253	    }
254	
255	    console.log('[main] Restart flag detected — restarting backend for rollback to', version);
256	
257	    try {
258	      await stopBackend();
259	      await startBackend();
260	
261	      // Reload all renderer windows so they pick up the restored frontend assets.
262	      for (const win of windows) {
263	        if (!win.isDestroyed()) {
264	          const frontendPath = getFrontendPath();
265	          if (IS_DEV || frontendPath.startsWith('http')) {
266	            win.loadURL(frontendPath);
267	          } else {
268	            win.loadFile(frontendPath);
269	          }
270	        }
271	      }
272	
273	      new Notification({
274	        title: 'MedOps — Rollback Complete',
275	        body: `System has been restored to ${version}. All windows reloaded.`,
276	      }).show();
277	    } catch (err) {
278	      dialog.showErrorBox(
279	        'MedOps — Restart Failed',
280	        `The backend could not restart after rollback.\n\n${(err as Error).message}\n\nPlease restart MedOps manually.`,
281	      );
282	    } finally {
283	      handling = false;
284	    }
285	  };
286	
287	  // Poll every 2 seconds — low overhead, no file-system watch dependency.
288	  setInterval(() => { void check(); }, 2000);
289	}
290	
291	// ─── Secret bootstrap ─────────────────────────────────────────────────────────
292	
293	interface AppSecrets {
294	  jwtSecret: string;
295	  encryptKey: string;
296	  hmacKey: string;
297	}
298	
299	/**
300	 * ensureSecrets — loads or generates the three backend secrets.
301	 *
302	 * Storage strategy (in priority order):
303	 *  1. Encrypted file via Electron safeStorage (OS DPAPI on Windows).
304	 *     File: <userData>/.secrets.enc  (binary, not human-readable)
305	 *  2. Plain-text fallback ONLY in dev mode (IS_DEV === true) where
306	 *     safeStorage may not be available and security requirements are relaxed.
307	 *
308	 * On packaged (non-dev) builds safeStorage is always available on Windows 10+.
309	 * If it is somehow unavailable the app shows an explicit error and quits — it
310	 * must NOT silently fall back to plaintext storage in production.
311	 */
312	function ensureSecrets(userDataDir: string): AppSecrets {
313	  mkdirSync(userDataDir, { recursive: true });
314	
315	  const encPath = join(userDataDir, '.secrets.enc');
316	  const legacyPath = join(userDataDir, '.secrets.json');
317	
318	  // --- Try loading from encrypted store ---
319	  if (safeStorage.isEncryptionAvailable()) {
320	    if (existsSync(encPath)) {
321	      try {
322	        const ciphertext = readFileSync(encPath);
323	        const plaintext = safeStorage.decryptString(ciphertext);
324	        const parsed = JSON.parse(plaintext) as Partial<AppSecrets>;
325	        if (parsed.jwtSecret && parsed.encryptKey && parsed.hmacKey) {
326	          // Clean up legacy plain file if it exists from an older build
327	          if (existsSync(legacyPath)) {
328	            try { unlinkSync(legacyPath); } catch { /* ignore */ }
329	          }
330	          return parsed as AppSecrets;
331	        }
332	      } catch (e) {
333	        console.warn('[main] Could not decrypt secrets file — regenerating', e);
334	      }
335	    }
336	
337	    // --- Generate and persist new secrets ---
338	    const secrets: AppSecrets = {
339	      jwtSecret: randomBytes(32).toString('hex'),
340	      encryptKey: randomBytes(32).toString('hex'),
341	      hmacKey: randomBytes(32).toString('hex'),
342	    };
343	    const ciphertext = safeStorage.encryptString(JSON.stringify(secrets));
344	    writeFileSync(encPath, ciphertext, { mode: 0o600 });
345	    // Remove any legacy plain file
346	    if (existsSync(legacyPath)) {
347	      try { unlinkSync(legacyPath); } catch { /* ignore */ }
348	    }
349	    console.log('[main] Generated and securely stored app secrets (safeStorage)');
350	    return secrets;
351	  }
352	
353	  // --- safeStorage not available ---
354	  if (!IS_DEV) {
355	    // In a packaged build this should never happen on Windows 10+.
356	    // Show a user-safe error and quit rather than silently using plaintext.
357	    dialog.showErrorBox(
358	      'MedOps — security error',
359	      'OS-level encryption (safeStorage) is not available on this system.\n\n' +
360	      'MedOps requires OS-level secret protection to start securely.\n' +
361	      'Ensure you are running Windows 10 or later and that the user profile is not corrupted.',
362	    );
363	    app.quit();
364	    // Unreachable after quit — satisfies TypeScript return type
365	    return { jwtSecret: '', encryptKey: '', hmacKey: '' };
366	  }
367	
368	  // Dev-mode only: plain JSON fallback so developers can run without packaging
369	  if (existsSync(legacyPath)) {
370	    try {
371	      const raw = JSON.parse(readFileSync(legacyPath, 'utf8')) as Partial<AppSecrets>;
372	      if (raw.jwtSecret && raw.encryptKey && raw.hmacKey) {
373	        return raw as AppSecrets;
374	      }
375	    } catch { /* regenerate */ }
376	  }
377	  const devSecrets: AppSecrets = {
378	    jwtSecret: randomBytes(32).toString('hex'),
379	    encryptKey: randomBytes(32).toString('hex'),
380	    hmacKey: randomBytes(32).toString('hex'),
381	  };
382	  writeFileSync(legacyPath, JSON.stringify(devSecrets), { mode: 0o600 });
383	  console.log('[main] Dev mode: stored secrets in plain JSON (safeStorage not available)');
384	  return devSecrets;
385	}
