387	async function stopBackend(): Promise<void> {
388	  if (backendProcess) {
389	    console.log('[main] Stopping backend...');
390	    backendProcess.kill('SIGTERM');
391	    backendProcess = null;
392	  }
393	  await embeddedPg?.stop();
394	  embeddedPg = null;
395	}
