401	  const ICON_B64 =
402	    'iVBORw0KGgoAAAANSUhEUgAAACAAAAAgCAYAAABzenr0AAAAAXNSR0IArs4c6QAAAARnQU1BAACx' +
403	    'jwv8YQUAAAAJcEhZcwAADsMAAA7DAcdvqGQAAABGSURBVFhH7c4xAQAgDASh/UdrjuAIXCTZ7AIA' +
404	    'AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA8G0BtAABhiK3KeEAAAAASUVORK5CYII=';
405	  return nativeImage.createFromBuffer(Buffer.from(ICON_B64, 'base64'));
406	}
