408	function createWindow(options: { url?: string; title?: string } = {}): BrowserWindow {
409	  const icon = createAppIcon();
410	  const win = new BrowserWindow({
411	    width: 1920,
412	    height: 1080,
413	    minWidth: 960,
414	    minHeight: 600,
415	    title: options.title ?? 'MedOps Offline Operations Console',
416	    icon,
417	    backgroundColor: '#f5f7fa',
418	    webPreferences: {
419	      preload: join(__dirname, 'preload.cjs'),
420	      contextIsolation: true,
421	      nodeIntegration: false,
422	      sandbox: true,
423	    },
424	    show: false, // shown after 'ready-to-show'
425	  });
