427	  // Resolve the asset path: active override > bundled > dev server.
428	  const frontendPath = options.url ?? getFrontendPath();
429	
430	  if (IS_DEV || frontendPath.startsWith('http')) {
431	    win.loadURL(frontendPath);
432	  } else {
433	    win.loadFile(frontendPath);
434	  }
435	
436	  win.once('ready-to-show', () => win.show());
