1	/**
2	 * System tray management for the MedOps desktop console.
3	 * Provides: open, backup, lock, new window, configurable reminders, and quit.
4	 *
5	 * Daily backup reminder persistence:
6	 *   The date of the last fired reminder is stored in a plain JSON file at
7	 *   `<userData>/tray-state.json` (via electron's `app.getPath('userData')`).
8	 *   On startup the file is read; the reminder fires at most once per calendar day.
9	 */
10	
11	import { Tray, Menu, Notification, app } from 'electron';
12	import { readFileSync, writeFileSync, existsSync } from 'fs';
13	import { join } from 'path';
14	
15	type TrayOptions = {
16	  icon: Electron.NativeImage;
17	  backendUrl: string;
18	  getAuthToken: () => Promise<string>;
19	  onOpen: () => void;
20	  onLock: () => void;
21	  onNewWindow: () => void;
22	  onBackup: () => void;
23	  onQuit: () => void;
24	};
25	
26	let tray: Tray | null = null;
27	let reminderInterval: ReturnType<typeof setInterval> | null = null;
28	let dailyReminderTimer: ReturnType<typeof setTimeout> | null = null;
29	let membershipReminderTimer: ReturnType<typeof setTimeout> | null = null;
30	let reminderMinutes = 0; // 0 = off
31	
32	// ─── Persistent state ─────────────────────────────────────────────────────────
33	
34	function statePath(): string {
35	  return join(app.getPath('userData'), 'tray-state.json');
36	}
37	
38	interface TrayState {
39	  lastBackupReminderDate: string | null; // ISO date string YYYY-MM-DD
40	  lastMembershipReminderDate: string | null;
41	}
42	
43	function loadState(): TrayState {
44	  try {
45	    if (existsSync(statePath())) {
46	      return JSON.parse(readFileSync(statePath(), 'utf8')) as TrayState;
47	    }
48	  } catch {
49	    // Corrupt file — start fresh
50	  }
51	  return { lastBackupReminderDate: null, lastMembershipReminderDate: null };
52	}
53	
54	function saveState(state: TrayState): void {
55	  try {
56	    writeFileSync(statePath(), JSON.stringify(state), 'utf8');
57	  } catch {
58	    // Non-fatal — reminder will just fire again next launch
59	  }
60	}
61	
62	function todayISO(): string {
63	  return new Date().toISOString().slice(0, 10); // YYYY-MM-DD
64	}
65	
66	// ─── Public API ───────────────────────────────────────────────────────────────
67	
68	/** Set up the system tray icon and context menu. */
69	export function setupTray(opts: TrayOptions): void {
70	  if (tray) return; // already set up
71	
72	  tray = new Tray(opts.icon);
73	  tray.setToolTip('MedOps Offline Operations Console');
74	  tray.on('double-click', opts.onOpen);
75	
76	  rebuildMenu(opts);
77	
78	  // Schedule once-per-day backup reminder.
79	  scheduleDailyBackupReminder(opts);
80	
81	  // Schedule membership expiry and low-stock checks.
82	  scheduleMembershipReminders(opts);
83	}
84	
85	/** Tear down the tray on app quit. */
86	export function cleanupTray(): void {
87	  clearReminder();
88	  if (dailyReminderTimer !== null) {
89	    clearTimeout(dailyReminderTimer);
90	    dailyReminderTimer = null;
91	  }
92	  if (membershipReminderTimer !== null) {
93	    clearTimeout(membershipReminderTimer);
94	    membershipReminderTimer = null;
95	  }
96	  tray?.destroy();
97	  tray = null;
98	}
99	
100	// ─── Menu builder ─────────────────────────────────────────────────────────────
101	
102	function rebuildMenu(opts: TrayOptions): void {
103	  if (!tray) return;
104	
105	  const reminderLabel =
106	    reminderMinutes > 0
107	      ? `Reminders: every ${reminderMinutes} min ✓`
108	      : 'Reminders: off';
109	
110	  const menu = Menu.buildFromTemplate([
111	    {
112	      label: 'Open MedOps Console',
113	      click: opts.onOpen,
114	    },
115	    { type: 'separator' },
116	    {
117	      label: 'Backup Now',
118	      click: () => {
119	        opts.onBackup();
120	        fireNotification('MedOps Backup', 'Backup started. You will be notified when it completes.', opts.onOpen);
121	      },
122	    },
123	    { type: 'separator' },
124	    {
125	      label: 'Lock Screen',
126	      accelerator: 'CmdOrCtrl+L',
127	      click: () => {
128	        opts.onLock();
129	        tray?.setToolTip('MedOps Console — Locked');
130	      },
131	    },
132	    { type: 'separator' },
133	    {
134	      label: reminderLabel,
135	      submenu: Menu.buildFromTemplate(
136	        [0, 15, 30, 60].map((minutes) => ({
137	          label: minutes === 0 ? 'Off' : `Every ${minutes} minutes`,
138	          type: 'radio' as const,
139	          checked: reminderMinutes === minutes,
140	          click: () => {
141	            reminderMinutes = minutes;
142	            setReminder(minutes, opts);
143	            rebuildMenu(opts);
144	          },
145	        })),
146	      ),
147	    },
148	    { type: 'separator' },
149	    {
150	      label: 'New Window',
151	      accelerator: 'CmdOrCtrl+N',
152	      click: opts.onNewWindow,
153	    },
154	    { type: 'separator' },
155	    {
156	      label: `Version ${app.getVersion()}`,
157	      enabled: false,
158	    },
159	    {
160	      label: 'Quit MedOps',
161	      accelerator: 'CmdOrCtrl+Q',
162	      click: opts.onQuit,
163	    },
164	  ]);
165	
166	  tray.setContextMenu(menu);
167	}
168	
169	// ─── Periodic reminder system (configurable interval) ─────────────────────────
170	
171	function clearReminder(): void {
172	  if (reminderInterval !== null) {
173	    clearInterval(reminderInterval);
174	    reminderInterval = null;
175	  }
176	}
177	
178	function setReminder(minutes: number, opts: TrayOptions): void {
179	  clearReminder();
180	  if (minutes === 0) return;
181	
182	  const ms = minutes * 60 * 1000;
183	  reminderInterval = setInterval(() => {
184	    fireNotification(
185	      'MedOps Reminder',
186	      'Time to check outstanding work orders and low-stock alerts.',
187	      opts.onOpen,
188	    );
189	  }, ms);
190	}
191	
192	// ─── Daily backup reminder ─────────────────────────────────────────────────────
193	// Fires at most once per calendar day. State persists to disk so restarting the
194	// app does not re-fire the reminder if it already fired today.
195	
196	function scheduleDailyBackupReminder(opts: TrayOptions): void {
197	  const state = loadState();
198	  const today = todayISO();
199	
200	  if (state.lastBackupReminderDate !== today) {
201	    // Has not fired today — schedule it for 30 seconds after startup so the
202	    // app is fully loaded, then reschedule for subsequent days.
203	    dailyReminderTimer = setTimeout(() => {
204	      fireDailyBackupReminder(opts);
205	    }, 30_000);
206	  } else {
207	    // Already fired today — schedule for midnight tonight.
208	    scheduleNextMidnight(opts);
209	  }
210	}
211	
212	function fireDailyBackupReminder(opts: TrayOptions): void {
213	  const state = loadState();
214	  state.lastBackupReminderDate = todayISO();
215	  saveState(state);
216	
217	  fireNotification(
218	    'MedOps Daily Backup Reminder',
219	    "Don't forget your daily backup. Click to open the console.",
220	    opts.onOpen,
221	  );
222	
223	  // Reschedule for next calendar day midnight.
224	  scheduleNextMidnight(opts);
225	}
226	
227	function scheduleNextMidnight(opts: TrayOptions): void {
228	  const now = new Date();
229	  const tomorrow = new Date(now.getFullYear(), now.getMonth(), now.getDate() + 1);
230	  const msUntilMidnight = tomorrow.getTime() - now.getTime();
231	
232	  dailyReminderTimer = setTimeout(() => {
233	    fireDailyBackupReminder(opts);
234	  }, msUntilMidnight);
235	}
236	
237	// ─── Membership / low-stock reminder ──────────────────────────────────────────
238	
239	function scheduleMembershipReminders(opts: TrayOptions): void {
240	  // Fire 60 seconds after startup, then every 24 hours.
241	  membershipReminderTimer = setTimeout(async () => {
242	    await checkMembershipAndStock(opts);
243	    // Reschedule every 24 hours.
244	    membershipReminderTimer = setInterval(async () => {
245	      await checkMembershipAndStock(opts);
246	    }, 24 * 60 * 60 * 1000) as unknown as ReturnType<typeof setTimeout>;
247	  }, 60_000);
248	}
249	
250	async function checkMembershipAndStock(opts: TrayOptions): Promise<void> {
251	  try {
252	    const token = await opts.getAuthToken();
253	    const authHeader = { Authorization: `Bearer ${token}` };
254	
255	    // Check members expiring soon via the role-unrestricted reminders endpoint.
256	    // Using /reminders/memberships instead of /members so any logged-in role
257	    // (maintenance_tech, learning_coordinator, etc.) can receive notifications —
258	    // not just front_desk/system_admin who have access to the full members list.
259	    const membersResp = await fetch(
260	      `${opts.backendUrl}/api/v1/reminders/memberships`,
261	      { headers: authHeader },
262	    );
263	    if (membersResp.ok) {
264	      const payload = await membersResp.json();
265	      const members: Array<{ name: string; expires_at: string }> = payload.data ?? [];
266	      const now = Date.now();
267	      for (const m of members) {
268	        const expiresMs = new Date(m.expires_at).getTime();
269	        const daysLeft = (expiresMs - now) / (1000 * 60 * 60 * 24);
270	        if (daysLeft < 0) continue; // already expired — skip
271	        if (daysLeft <= 1) {
272	          fireNotification(
273	            'URGENT: Membership Expiring Today',
274	            `URGENT: Member ${m.name} expires today!`,
275	            opts.onOpen,
276	          );
277	        } else if (daysLeft <= 7) {
278	          const n = Math.ceil(daysLeft);
279	          fireNotification(
280	            'Membership Expiry Warning',
281	            `Member ${m.name} membership expires in ${n} days`,
282	            opts.onOpen,
283	          );
284	        } else if (daysLeft <= 14) {
285	          const n = Math.ceil(daysLeft);
286	          fireNotification(
287	            'Membership Expiry Reminder',
288	            `Reminder: Member ${m.name} membership expires in ${n} days`,
289	            opts.onOpen,
290	          );
291	        }
292	      }
293	    }
294	
295	    // Check low-stock SKUs via the role-unrestricted reminder endpoint.
296	    // Using /reminders/low-stock instead of /skus/low-stock so any logged-in role
297	    // (front_desk, maintenance_tech, etc.) receives the alert — not just
298	    // inventory_pharmacist/system_admin who have access to the full SKU endpoint.
299	    const stockResp = await fetch(
300	      `${opts.backendUrl}/api/v1/reminders/low-stock`,
301	      { headers: authHeader },
302	    );
303	    if (stockResp.ok) {
304	      const stockPayload = await stockResp.json();
305	      const count: number = stockPayload.count ?? 0;
306	      if (count > 0) {
307	        fireNotification(
308	          'Low Stock Alert',
309	          `${count} SKU(s) are below low-stock threshold`,
310	          opts.onOpen,
311	        );
312	      }
313	    }
314	  } catch {
315	    // Non-fatal — silently ignore errors
316	  }
317	}
318	
319	// ─── Notification helper ───────────────────────────────────────────────────────
320	
321	function fireNotification(title: string, body: string, onClick: () => void): void {
322	  if (!Notification.isSupported()) return;
323	
324	  const n = new Notification({ title, body, timeoutType: 'default' });
325	  n.on('click', onClick);
326	  n.show();
327	}
