1	/**
2	 * System tray management for the MedOps desktop console.
3	 * Provides: open, backup, lock, new window, configurable reminders, and quit.
4	 *
5	 * Daily backup reminder persistence:
6	 *   The date of the last fired reminder is stored in a plain JSON file at
7	 *   `<userData>/tray-state.json` (via electron's `app.getPath('userData')`).
8	 *   On startup the file is read; the reminder fires at most once per calendar day.
9	 */
10	
11	import { Tray, Menu, Notification, app } from 'electron';
12	import { readFileSync, writeFileSync, existsSync } from 'fs';
13	import { join } from 'path';
14	
15	type TrayOptions = {
16	  icon: Electron.NativeImage;
17	  backendUrl: string;
18	  getAuthToken: () => Promise<string>;
19	  onOpen: () => void;
20	  onLock: () => void;
21	  onNewWindow: () => void;
22	  onBackup: () => void;
23	  onQuit: () => void;
24	};
25	
26	let tray: Tray | null = null;
27	let reminderInterval: ReturnType<typeof setInterval> | null = null;
28	let dailyReminderTimer: ReturnType<typeof setTimeout> | null = null;
29	let membershipReminderTimer: ReturnType<typeof setTimeout> | null = null;
30	let reminderMinutes = 0; // 0 = off
31	
32	// ─── Persistent state ─────────────────────────────────────────────────────────
33	
34	function statePath(): string {
35	  return join(app.getPath('userData'), 'tray-state.json');
36	}
37	
38	interface TrayState {
39	  lastBackupReminderDate: string | null; // ISO date string YYYY-MM-DD
40	  lastMembershipReminderDate: string | null;
41	}
42	
43	function loadState(): TrayState {
44	  try {
45	    if (existsSync(statePath())) {
46	      return JSON.parse(readFileSync(statePath(), 'utf8')) as TrayState;
47	    }
48	  } catch {
49	    // Corrupt file — start fresh
50	  }
51	  return { lastBackupReminderDate: null, lastMembershipReminderDate: null };
52	}
53	
54	function saveState(state: TrayState): void {
55	  try {
56	    writeFileSync(statePath(), JSON.stringify(state), 'utf8');
57	  } catch {
58	    // Non-fatal — reminder will just fire again next launch
59	  }
60	}
61	
62	function todayISO(): string {
63	  return new Date().toISOString().slice(0, 10); // YYYY-MM-DD
64	}
65	
66	// ─── Public API ───────────────────────────────────────────────────────────────
67	
68	/** Set up the system tray icon and context menu. */
69	export function setupTray(opts: TrayOptions): void {
70	  if (tray) return; // already set up
71	
72	  tray = new Tray(opts.icon);
73	  tray.setToolTip('MedOps Offline Operations Console');
74	  tray.on('double-click', opts.onOpen);
75	
76	  rebuildMenu(opts);
77	
78	  // Schedule once-per-day backup reminder.
79	  scheduleDailyBackupReminder(opts);
