279	interface BatchStub { id: string; expiration_date: string; quantity_on_hand: number }
280	
281	function fefoSelectForAdjust(batches: BatchStub[], qty: number): BatchStub | null {
282	  const now = new Date();
283	  const nonExpired = batches.filter(b => new Date(b.expiration_date) > now);
284	  if (nonExpired.length === 0) return null;
285	  nonExpired.sort((a, b) =>
286	    new Date(a.expiration_date).getTime() - new Date(b.expiration_date).getTime()
287	  );
288	  if (qty > 0) return nonExpired[0]; // addition: earliest expiry
289	  return nonExpired.find(b => b.quantity_on_hand + qty >= 0) ?? null;
290	}
