479	      ['1.1.0', '1.2.0'],
480	    );
481	    let h = history;
482	    h = afterRollback(h); // rolls back to 1.1.0
483	    h = afterRollback(h); // rolls back to 1.0.0
484	    h = afterRollback(h); // rolls back to baseline
485	    expect(h).toHaveLength(0);
