487	
488	  it('artifact_dir and backup_file reference the same update epoch (timestamp)', () => {
489	    const [entry] = buildVersionHistory(['1.0.0', '1.1.0']);
490	    const backupStamp = entry.backup_file.match(/\d{8}T\d{6}Z/)?.[0];
