250	async function checkMembershipAndStock(opts: TrayOptions): Promise<void> {
251	  try {
252	    const token = await opts.getAuthToken();
253	    const authHeader = { Authorization: `Bearer ${token}` };
254	
255	    // Check members expiring soon via the role-unrestricted reminders endpoint.
256	    // Using /reminders/memberships instead of /members so any logged-in role
257	    // (maintenance_tech, learning_coordinator, etc.) can receive notifications —
258	    // not just front_desk/system_admin who have access to the full members list.
259	    const membersResp = await fetch(
260	      `${opts.backendUrl}/api/v1/reminders/memberships`,
261	      { headers: authHeader },
262	    );
263	    if (membersResp.ok) {
264	      const payload = await membersResp.json();
265	      const members: Array<{ name: string; expires_at: string }> = payload.data ?? [];
266	      const now = Date.now();
267	      for (const m of members) {
268	        const expiresMs = new Date(m.expires_at).getTime();
269	        const daysLeft = (expiresMs - now) / (1000 * 60 * 60 * 24);
270	        if (daysLeft < 0) continue; // already expired — skip
271	        if (daysLeft <= 1) {
272	          fireNotification(
273	            'URGENT: Membership Expiring Today',
274	            `URGENT: Member ${m.name} expires today!`,
275	            opts.onOpen,
276	          );
277	        } else if (daysLeft <= 7) {
278	          const n = Math.ceil(daysLeft);
279	          fireNotification(
280	            'Membership Expiry Warning',
281	            `Member ${m.name} membership expires in ${n} days`,
282	            opts.onOpen,
283	          );
284	        } else if (daysLeft <= 14) {
285	          const n = Math.ceil(daysLeft);
286	          fireNotification(
287	            'Membership Expiry Reminder',
288	            `Reminder: Member ${m.name} membership expires in ${n} days`,
289	            opts.onOpen,
290	          );
291	        }
292	      }
293	    }
294	
295	    // Check low-stock SKUs via the role-unrestricted reminder endpoint.
