297	    // (front_desk, maintenance_tech, etc.) receives the alert — not just
298	    // inventory_pharmacist/system_admin who have access to the full SKU endpoint.
299	    const stockResp = await fetch(
300	      `${opts.backendUrl}/api/v1/reminders/low-stock`,
