5	export function useAuth() {
6	  const [user, setUser] = useState<User | null>(() => {
7	    const stored = localStorage.getItem('medops_user');
8	    return stored ? JSON.parse(stored) : null;
9	  });
10	  const [loading, setLoading] = useState(false);
11	  const [error, setError] = useState<string | null>(null);
12	  // bootstrapping is true while we are validating a stored token against /auth/me.
13	  // Protected routes must gate rendering until this is false.
14	  const [bootstrapping, setBootstrapping] = useState(() => !!localStorage.getItem('medops_token'));
15	
16	  // On mount: validate stored token with the server. If the token is expired or
17	  // revoked, the server returns 401 and the axios interceptor clears localStorage
18	  // and redirects to /login. We also clear local state here to be safe.
19	  useEffect(() => {
20	    const token = localStorage.getItem('medops_token');
21	    if (!token) {
22	      setBootstrapping(false);
23	      return;
24	    }
25	    authAPI.getMe()
26	      .then(res => setUser(res.data))
27	      .catch(() => {
28	        localStorage.removeItem('medops_token');
29	        localStorage.removeItem('medops_user');
30	        setUser(null);
31	      })
32	      .finally(() => setBootstrapping(false));
33	  // eslint-disable-next-line react-hooks/exhaustive-deps
34	  }, []);
35	
36	  const login = useCallback(async (username: string, password: string) => {
37	    setLoading(true);
38	    setError(null);
39	    try {
40	      const res = await authAPI.login(username, password);
41	      const { token, user: userData } = res.data;
42	      localStorage.setItem('medops_token', token);
43	      localStorage.setItem('medops_user', JSON.stringify(userData));
44	      setUser(userData);
45	      return userData;
46	    } catch (err: any) {
47	      const msg = err.response?.data?.error || 'Login failed';
48	      setError(msg);
49	      throw new Error(msg);
50	    } finally {
51	      setLoading(false);
52	    }
53	  }, []);
54	
55	  const logout = useCallback(async () => {
56	    try {
